impl Solution { pub fn flipgame(black_fronts: Vec<i32>, black_backs: Vec<i32>) -> i32 { let mut black_forbidden = std::collections::HashSet::new(); for i in 0..black_fronts.len() { if black_fronts[i] == black_backs[i] { black_forbidden.insert(black_fronts[i]); } } let mut black_res = 3000; for &x in black_fronts.iter().chain(black_backs.iter()) { if !black_forbidden.contains(&x) { black_res = black_res.min(x); } } if black_res == 3000 { 0 } else { black_res } } }